var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐, 뭐야. 해치웠어......?","JPN":"な、何なの、始末できたというのですか……？","ENG":"H-how is that possible? You wiped them out so easily!","TWN":"什，什麼。解決掉了嗎……？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"잔챙이들은 대부분 처리한 것 같네요, 스승님.","JPN":"雑魚どもはだいたい片付いたみたいですね、師匠。","ENG":"We took care of most small fry, Master.","TWN":"師父，看來那些雜魚被收拾的差不多了。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 이제 곧 나타나겠군.","JPN":"ああ、じきに奴が現れそうだ。","ENG":"We did. Our real prey will show up soon.","TWN":"好。應該馬上就要出現了。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"잔챙이라니......","JPN":"雑魚どもって……","ENG":"Small fry?","TWN":"竟然說是雜魚……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이것들 하나하나가...... 우리 세계에선 국가의 존속을 위협하는 괴물들인데......","JPN":"それぞれの個体が……私たちの世界では、国の存続を脅かす化け物だというのに……","ENG":"Each and every single one of them could have threatened the existence of a country in our world.","TWN":"它們每一個……在我們的世界裡，都是威脅到國家存亡的怪物啊……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"차원 통로로부터 흘러나오는 힘이 강해지고 있다.","JPN":"次元間通路から流れ出る力が強まっている。","ENG":"The energy leaking from the dimensional passageway is growing stronger.","TWN":"從次元通道流出的力量越來越強。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"사냥감이 가까이 오고 있나 보군. 준비해라.","JPN":"獲物が近づいてきてる、構えろ。","ENG":"The Prey is near. Get ready.","TWN":"看來獵物接近了。做好準備。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"등급은 어느 정도죠?","JPN":"ランクはどのくらいです？","ENG":"To which category do you think it belongs?","TWN":"等級大概是？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"느껴지는 수준은 4종 중급 침식체 정도군.","JPN":"第4種の中級侵食体程度だな。","ENG":"As far as I can tell, Category 4. Middle class.","TWN":"憑感覺來看，應該是第4級的中級侵蝕體。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"확실한 건 직접 봐야 알겠지만.","JPN":"直接見てみないと確信はできないがな。","ENG":"I won't know until I see it, though.","TWN":"雖然得親眼看到才能確認。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"클리포트 인자를 가진 사냥감치고는 무난한 편이군요.","JPN":"クリフォト・ファクター所持の獲物にしては無難なほうですね。","ENG":"It wouldn't be too difficult for Prey with the Qliphoth Factor.","TWN":"以擁有逆卡巴拉因子的獵物來說，還算過得去。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"항상 하던 대로 스승님이 전방을, 제가 지원을 맡으면 될까요?","JPN":"いつも通り、師匠は前方、僕は支援担当でいいですか？","ENG":"Are we doing what we always do, you at the front and me in the rear?","TWN":"那就像往常一樣，師父負責前方，我負責支援嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그렇긴 한데...... 생각보다 침식체들이 많이 몰려오는군.","JPN":"それでいいが……思ったよりも侵食体の数が多いぞ。","ENG":"Sure, but we're getting more C.O.s than I thought.","TWN":"但是這……聚集的侵蝕體比想像來得還要多。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주변에 방해꾼들이 많다면 우리 둘만으로는 조금 귀찮아질 수도 있겠어.","JPN":"周辺に邪魔者が多い場合は、私たちだけじゃ少し手こずるかもしれないな。","ENG":"Having too many of them can get in our way of hunting the Prey.","TWN":"周圍妨礙者太多的話，光靠我們兩個可能會有些麻煩。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......거기!","JPN":"……そこ！","ENG":"Hey, illegal dumpers over there.","TWN":"……喂！"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"쓰레기 무단투기꾼 아가씨들은 어떻게 할지 정했나?","JPN":"ゴミの不法投棄にきた小娘たち。どうするか決めたのか？","ENG":"Have you decided what you want to do?","TWN":"隨便傾倒垃圾的小姐，你們決定好要怎麼做了嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"정말로...... 놈을 쓰러트릴 수 있는 건가요? 그 끔찍한 괴물을?","JPN":"本当に……奴を倒せるんですか？　あの忌々しい化け物を？","ENG":"Can you... Can you really bring it down? That terrible monster?","TWN":"真的……可以打倒它們嗎？打倒那可怕的怪物？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"세상 일에 <color=#ffd34c>절대</color> 라는 게 어디 있겠습니까?","JPN":"世の中に<color=#ffd34c>絶対</color>なんてありませんよ。","ENG":"Nothing in the world is <color=#ffd34c>absolute</color>,","TWN":"世上哪有 <color=#ffd34c>絕對</color> 的事情？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 저희가 침식체를 상대하는 걸 지켜 보셨으니 결정은 여러분의 몫이겠죠.","JPN":"でも、僕たちと侵食体の戦いを見てもらいましたし、どうするのかはあなたたち次第です。","ENG":"but you saw how we dealt with the C.O.s. We'll let you decide.","TWN":"不過，既然都看到我們是怎麼對付侵蝕體的，接下來就看你們是怎麼決定了。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는...... 저는......","JPN":"私……私は……","ENG":"I... I...","TWN":"我……我……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신들이 허락해 준다면, 저는 당신들과 함께 싸우고 싶어요.","JPN":"あなた方が認めてくれるなら、私は一緒に戦いたいです。","ENG":"I'd like to fight alongside you. If you allow me, that is.","TWN":"如果你們允許，我想和你們一起戰鬥。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"놈에게 많은 사람들이...... 그리고 제 동료들이 희생됐어요.","JPN":"奴の手で、大勢の人々が……私の仲間たちが、犠牲になりました。","ENG":"That monster killed a lot of people, including my comrades.","TWN":"那傢伙可是把很多人……而且我的很多同事也犧牲了。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"물론 제가 이 세계에 한 일은 용서받을 수 없는 일이지만......","JPN":"もちろん、私がこの世界にしてしまったことは、許されないと思いますが……","ENG":"I know what I did to your world is unforgivable.","TWN":"當然，我對這個世界所做的事情是不可原諒的……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 저주받을 네피림을 처치할 수만 있다면 어떤 대가를 치르더라도 상관없습니다.","JPN":"あの忌々しいネフィリムを退治できるなら、どんな代償を払ってもかまいません。","ENG":"I'll take whatever punishment you have in store for me, after we take care of that cursed Nephil.","TWN":"但只要能消滅諾菲力，不管要付出什麼代價我都無所謂。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"제가...... 같이 싸워도 될까요? 절 용서해 주시겠어요?","JPN":"私も……一緒に戦ってもいいですか？　私のこと、許していただけますか？","ENG":"So... would you let me fight alongside you? Would you... forgive me?","TWN":"我……可以一起戰鬥嗎？你們可以原諒我嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"누굴 용서하고 말고 할 입장은 아니라서 그건 어렵겠군.","JPN":"許す、許さないを決められる立場ではないから、それは難しいな。","ENG":"It's not my place to forgive you, or anyone else for that matter.","TWN":"我的立場也沒辦法決定要不要去原諒誰，這還挺難辦的呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 놈을 사냥하는 건 어차피 내가 해야 될 일이다.","JPN":"だが、奴を退治するのはどのみち私の任務だ。","ENG":"But it's my job to hunt that C.O.","TWN":"但狩獵怪物畢竟是我的工作。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"돕겠다는 걸 마다할 이유는 없어.","JPN":"加勢を断る理由もあるまい。","ENG":"If you want to help, I have no reason to say no.","TWN":"我沒有理由拒絕幫助。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 네피림이라는 놈은 나와 제자 녀석이 상대하겠다.","JPN":"あのネフィリムという奴は、私と弟子で相手する。","ENG":"My apprentice and I'll take care of the Nephil.","TWN":"那個叫諾菲力的傢伙由我和我的徒弟來對付。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너희들에겐 주변에 몰려드는 침식체들을 부탁하지.","JPN":"お前たちには、周辺に押し寄せる侵食体の相手を頼もう。","ENG":"In the meantime, I want you to keep other C.O.s away from us.","TWN":"你們負責四周圍過來的侵蝕體吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"할 수 있겠나?","JPN":"できるか？","ENG":"Can you do that?","TWN":"能做到嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"물론입니다! 목숨을 바쳐서라도 침식체들이 당신들을 방해하지 못하도록 막겠어요!","JPN":"もちろんです！　命を捧げてでも、侵食体があなた方を邪魔できないように防ぎます！","ENG":"Absolutely. I'll keep them away from you even if it kills me.","TWN":"當然！我會賭上性命，不讓那些侵蝕體妨礙你們的！"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 거기에 대해서 말인데요.","JPN":"あ、そこなんですけど。","ENG":"Ah, about that.","TWN":"啊，關於那個，我有些想說的。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"도와줄 사람은 많으면 많을수록 좋지 않겠어요?","JPN":"援軍は多ければ多いほど良いですよね？","ENG":"The more the merrier, right?","TWN":"幫忙的人當然是越多越好，對吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네? 또 무슨 엉뚱한 생각을 하는 거죠, 시영 씨?!","JPN":"えっ？　また何を企んでるんです、シノンさん！？","ENG":"Huh? What are you up to this time, Shiyoung?","TWN":"咦？妳又在想什麼餿主意了，時雨小姐？！"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"엉뚱하다니 섭섭한 소릴 하시네요. 기억 안 나세요?","JPN":"企むだなんて、なんて悲しいことを。あれ、覚えていませんか？","ENG":"Nothing. Why do you think I'm always up to something? Did you forget?","TWN":"居然說是餿主意，好傷心啊。妳不記得了嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아주 유능한 잠재적 아군이 근처에 한 분 있으시잖아요.","JPN":"非常に有能な「潜在的」な味方が一人、近くにいるじゃないですか。","ENG":"You've got a very competent potential ally nearby.","TWN":"附近不是潛藏著一位強大的友軍嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};